SELECT  FROM jst_sales_channel_binding

    AND channel_id = #{channelId}
    AND sales_id = #{salesId}
    AND bind_source = #{bindSource}

ORDER BY effective_from DESC

mapper.update:
UPDATE jst_sales_channel_binding
channel_id = #{channelId}, sales_id = #{salesId}, effective_from = #{effectiveFrom}, effective_to = #{effectiveTo}, bind_source = #{bindSource}, bind_remark = #{bindRemark}, operator_id = #{operatorId}, update_by = #{updateBy}, update_time = NOW()
WHERE binding_id = #{bindingId}

mapper.select:
SELECT  FROM jst_sales_channel_binding
 WHERE channel_id = #{channelId}
   AND effective_from <= #{atTime}
   AND (effective_to IS NULL OR effective_to > #{atTime})
 LIMIT 1
